//#region src/highlight/config.ts
/** define shared configurations for Shiki */
function defineShikiConfig(config) {
	let created;
	return {
		id: Symbol(),
		defaultThemes: config.defaultThemes,
		resolveThemes(options = {}) {
			let out;
			if (!("theme" in options) && !("themes" in options)) out = config.defaultThemes;
			else out = options;
			if ("themes" in out && out.defaultColor === void 0) return {
				...out,
				defaultColor: false
			};
			return out;
		},
		createHighlighter() {
			if (created) return created;
			created = config.createHighlighter();
			if ("then" in created) created = created.then((v) => created = v);
			return created;
		}
	};
}
//#endregion
export { defineShikiConfig };
